import { Content, EmbedContentConfig, FunctionDeclaration, GenerateContentParameters, GenerateContentResponse, GoogleGenAI, Part } from "@google/genai";
import { App, Notice } from "obsidian";
import { z } from "zod";

import { MODEL_CONSTANTS, SEARCH_CONSTANTS } from "../constants";
import { VaultIntelligenceSettings } from "../settings";
import { ChatOptions, IEmbeddingClient, IModelProvider, IReasoningClient, IToolDefinition, ProviderError, StreamChunk, ToolCall, UnifiedMessage } from "../types/providers";
import { logger } from "../utils/logger";
import { ModelRegistry } from "./ModelRegistry";

interface InternalSecretStorage {
    getSecret(key: string): string | null;
}

export interface EmbedOptions {
    outputDimensionality?: number;
    taskType?: string;
    title?: string;
}

/** Interface for Phase 8 SDK unification fix */
interface UnifiedSDKParams extends GenerateContentParameters {
    system_instruction?: unknown;
    systemInstruction?: unknown;
    tools?: unknown;
}


export class GeminiProvider implements IModelProvider, IReasoningClient, IEmbeddingClient {
    private client: GoogleGenAI | null = null;
    private settings: VaultIntelligenceSettings;
    private app: App;

    // --- IModelProvider Capabilities ---
    public readonly supportsTools = true;
    public readonly supportsStructuredOutput = true;
    public readonly supportsWebGrounding = true;
    public readonly supportsCodeExecution = true;

    constructor(settings: VaultIntelligenceSettings, app: App) {
        this.settings = settings;
        this.app = app;
    }

    /**
     * Resolves the actual Google API key.
     * Handles SecretStorage ID lookup vs Legacy plain text fallback.
     */
    public async getApiKey(): Promise<string | null> {
        const storedValue = this.settings.googleApiKey;
        if (!storedValue) return null;

        if (this.settings.secretStorageFailure || storedValue.startsWith('AIza')) {
            return storedValue;
        }

        if (storedValue) {
            try {
                const storage = this.app.secretStorage as unknown as InternalSecretStorage | undefined;
                if (storage && storage.getSecret) {
                    return Promise.resolve(storage.getSecret(storedValue));
                }
                return null;
            } catch (error) {
                logger.error("Failed to retrieve secret from storage:", error);
                return null;
            }
        }
        return null;
    }

    private async getClient(): Promise<GoogleGenAI> {
        if (this.client) return this.client;

        const apiKey = await this.getApiKey();
        if (!apiKey) {
            if (this.settings.googleApiKey && !this.settings.googleApiKey.startsWith('AIza')) {
                new Notice("API key not found in this device's keychain. Please re-select it in settings.");
            }
            throw new ProviderError("Google API Key is missing or could not be retrieved.", "google");
        }

        try {
            this.client = new GoogleGenAI({ apiKey });
            logger.info("GeminiProvider initialized with resolved key.");
            return this.client;
        } catch (error: unknown) {
            const message = error instanceof Error ? error.message : String(error);
            throw new ProviderError(`Failed to initialize Gemini client: ${message}`, "google");
        }
    }

    public updateSettings(settings: VaultIntelligenceSettings) {
        this.settings = settings;
        this.client = null; // Force re-initialization on next call
    }

    public isReady(): boolean {
        return !!this.client || (!!this.settings.googleApiKey && !this.settings.secretStorageFailure);
    }

    // --- IReasoningClient Implementation ---

    public async generateMessage(messages: UnifiedMessage[], options: ChatOptions): Promise<UnifiedMessage> {
        return this.retryOperation(async () => {
            const client = await this.getClient();
            const contents = this.formatHistory(messages);
            const tools = this.formatTools(options.tools);

            const modelDef = options.modelId ? ModelRegistry.getModelById(options.modelId) : undefined;
            const useNativeSearch = modelDef?.supportsNativeSearch;

            let systemInstruction = options.systemInstruction;

            // System instructions fallback
            // Extract the 'system' roles and map them to systemInstructions if not explicitly provided
            if (!systemInstruction) {
                const sysMsgs = messages.filter(m => m.role === 'system');
                if (sysMsgs.length > 0) {
                    systemInstruction = sysMsgs.map(m => m.content).join("\n");
                }
            }

            // Phase 8 SDK unification fix: Move tools and systemInstruction to top-level as well as config
            const requestParams: UnifiedSDKParams = {
                config: {},
                contents: contents,
                model: options.modelId || this.settings.chatModel
            };

            const toolObjects: unknown[] = [];
            if (tools && tools.length > 0) {
                toolObjects.push({ functionDeclarations: tools });
            }
            if (useNativeSearch) {
                toolObjects.push({ googleSearch: {} });
            }

            if (toolObjects.length > 0) {
                requestParams.tools = toolObjects;
                requestParams.config!.tools = toolObjects;
            }

            if (systemInstruction) {
                requestParams.systemInstruction = systemInstruction;
                requestParams.system_instruction = systemInstruction; // SDK 2.0 fallback
                requestParams.config!.systemInstruction = systemInstruction;
            }

            logger.debug("[Agent] Final Request Params", requestParams);

            const response = await client.models.generateContent(requestParams);
            const parsed = this.parseResponse(response);

            const candidate = response.candidates?.[0];
            const groundingChunks = (candidate as unknown)?.groundingMetadata?.groundingChunks || [];
            const citations: string[] = [];
            for (const gc of groundingChunks) {
                if (gc.web?.uri && gc.web?.title) {
                    const citation = `[${gc.web.title}](${gc.web.uri})`;
                    if (!citations.includes(citation)) citations.push(citation);
                }
            }
            if (citations.length > 0 && parsed.content) {
                 const formattedCitations = "\n\n---\n**Sources:**\n" + citations.map((c, i) => `[${i + 1}] ${c}`).join("\n");
                 parsed.content = parsed.content.trimEnd() + formattedCitations;
            }

            return parsed;
        });
    }

    public async *generateMessageStream(messages: UnifiedMessage[], options: ChatOptions): AsyncIterableIterator<StreamChunk> {
        const client = await this.getClient();
        const contents = this.formatHistory(messages);
        const tools = this.formatTools(options.tools);

        const modelDef = options.modelId ? ModelRegistry.getModelById(options.modelId) : undefined;
        const useNativeSearch = modelDef?.supportsNativeSearch;

        let systemInstruction = options.systemInstruction;
        if (!systemInstruction) {
            const sysMsgs = messages.filter(m => m.role === 'system');
            if (sysMsgs.length > 0) {
                systemInstruction = sysMsgs.map(m => m.content).join("\n");
            }
        }

        // Phase 8 SDK unification fix: Move tools and systemInstruction to top-level as well as config
        const requestParams: UnifiedSDKParams = {
            config: {},
            contents: contents,
            model: options.modelId || this.settings.chatModel
        };

        const toolObjects: unknown[] = [];
        if (tools && tools.length > 0) {
            toolObjects.push({ functionDeclarations: tools });
        }
        if (useNativeSearch) {
            toolObjects.push({ googleSearch: {} });
        }

        if (toolObjects.length > 0) {
            requestParams.tools = toolObjects;
            requestParams.config!.tools = toolObjects;
        }

        if (systemInstruction) {
            requestParams.systemInstruction = systemInstruction;
            requestParams.system_instruction = systemInstruction; // SDK 2.0 fallback
            requestParams.config!.systemInstruction = systemInstruction;
        }

        logger.debug("[Agent] Final Request Params", requestParams);

        const streamResponse = await client.models.generateContentStream(requestParams);

        const accumulatedParts: Part[] = [];
        let activeThoughtSignature: string | undefined;
        const citations: string[] = [];
        let fullText = "";

        try {
            for await (const chunk of streamResponse) {
                if (options.signal?.aborted) {
                    break;
                }

                const candidate = chunk.candidates?.[0];
                const groundingChunks = (candidate as unknown)?.groundingMetadata?.groundingChunks || [];
                for (const gc of groundingChunks) {
                    if (gc.web?.uri && gc.web?.title) {
                        const citation = `[${gc.web.title}](${gc.web.uri})`;
                        if (!citations.includes(citation)) citations.push(citation);
                    }
                }

                if (candidate?.content?.parts) {
                    accumulatedParts.push(...candidate.content.parts);

                    // Capture thought_signature if present in this chunk
                    candidate.content.parts.forEach(part => {
                        const partObj = part as Record<string, unknown>;
                        if (typeof partObj['thought_signature'] === 'string') {
                            activeThoughtSignature = partObj['thought_signature'];
                        }
                    });
                }

                const parsed = this.parseResponse(chunk);
                if (parsed.content) {
                    fullText += parsed.content;
                    yield { text: parsed.content };
                }
            }

            if (!options.signal?.aborted) {
                if (citations.length > 0) {
                    const formattedCitations = "\n\n---\n**Sources:**\n" + citations.map((c, i) => `[${i + 1}] ${c}`).join("\n");
                    yield { replaceText: fullText.trimEnd() + formattedCitations };
                }

                if (accumulatedParts.length > 0) {
                // Yield the fully aggregated tool calls once at the end.
                // Re-parsing all parts ensures complete functionCall arguments.
                const finalParsed = this.parseResponse({
                    candidates: [{
                        content: { parts: accumulatedParts }
                    }]
                } as unknown as GenerateContentResponse);

                if (finalParsed.toolCalls && activeThoughtSignature) {
                    finalParsed.toolCalls.forEach(call => {
                        if (!call.thought_signature) {
                            call.thought_signature = activeThoughtSignature;
                        }
                    });
                }

                yield {
                    isDone: true,
                    rawContent: accumulatedParts,
                    toolCalls: finalParsed.toolCalls
                };
            }
            }
        } catch (error: unknown) {
            const message = error instanceof Error ? error.message : String(error);
            if (message.includes("429")) {
                throw new ProviderError("Rate limit exceeded during streaming", "google", 429);
            }
            throw new ProviderError(`Streaming error: ${message}`, "google");
        }
    }

    public async generateStructured<T>(messages: UnifiedMessage[], schema: z.ZodType<T>, options: ChatOptions): Promise<T> {
        return this.retryOperation(async () => {
            const client = await this.getClient();
            const contents = this.formatHistory(messages);

            // Use explicit JSON schema from options if provided (Phase 1 stabilization)
            // fallback logic: options.jsonSchema -> existing _def hack (for future-proofing) -> tools parameters -> default 
            const responseSchema = options?.jsonSchema || 
                                 (schema as unknown as { _def: { jsonSchema?: Record<string, unknown> } })._def?.jsonSchema || 
                                 options?.tools?.[0]?.parameters || 
                                 { type: "object" };

            // Phase 8 SDK unification fix: Move systemInstruction to top-level as well as config
            const requestParams: UnifiedSDKParams = {
                config: {
                    responseMimeType: "application/json",
                    responseSchema: responseSchema as Record<string, unknown>
                },
                contents: contents,
                model: options.modelId || this.settings.chatModel
            };

            if (options.systemInstruction) {
                requestParams.systemInstruction = options.systemInstruction;
                requestParams.system_instruction = options.systemInstruction; // SDK 2.0 fallback
                requestParams.config!.systemInstruction = options.systemInstruction;
            }

            logger.debug("[Agent] Final Request Params (Structured)", requestParams);

            const response = await client.models.generateContent(requestParams);

            const text = response.text || "{}";
            try {
                return schema.parse(JSON.parse(text));
            } catch (error: unknown) {
                const message = error instanceof Error ? error.message : String(error);
                throw new ProviderError(`Failed to parse structured output: ${message}`, "google");
            }
        });
    }

    // --- Adapters Data Mapping ---

    private formatHistory(messages: UnifiedMessage[]): Content[] {
        const filtered = messages.filter(m => m.role !== 'system');
        if (filtered.length === 0) return [];

        const merged: Content[] = [];
        let currentRole: Content['role'] | null = null;
        let currentParts: Content['parts'] = [];

        for (const m of filtered) {
            let parts: Part[] = [];

            if (m.rawContent && m.rawContent.length > 0) {
                parts = [...(m.rawContent as Part[])];
            } else {
                if (m.content) {
                    parts.push({ text: m.content });
                }

                if (m.role === 'model' && m.toolCalls && m.toolCalls.length > 0) {
                    m.toolCalls.forEach((call) => {
                        const fc: Part['functionCall'] = {
                            args: call.args,
                            name: call.name
                        };
                        const part: Record<string, unknown> = { functionCall: fc };
                        // Sibling placement: thought_signature belongs on the Part object, not inside functionCall
                        if (call.thought_signature) {
                            part['thought_signature'] = call.thought_signature;
                        }
                        parts.push(part as unknown as Part);
                    });
                } else if (m.role === 'tool' && m.toolResults && m.toolResults.length > 0) {
                    m.toolResults.forEach(res => {
                        const fr: Part['functionResponse'] = {
                            name: res.name,
                            response: res.result
                        };
                        parts.push({ functionResponse: fr as unknown as Part['functionResponse'] } as Part);
                    });
                } else if (m.role === 'user' && m.name && m.toolCalls && m.toolCalls.length > 0) {
                    // Legacy fallback (Phase 1 stabilization)
                    parts.push({
                        functionResponse: {
                            name: m.name,
                            response: (m.toolCalls?.[0]?.args as Record<string, unknown>) || undefined
                        }
                    });
                }
            }

            const mappedRole: Content['role'] = (m.role === 'tool' || m.role === 'user') ? 'user' : 'model';

            if (mappedRole === currentRole) {
                currentParts.push(...parts);
            } else {
                if (currentRole !== null && currentParts.length > 0) {
                    merged.push({ parts: currentParts, role: currentRole });
                }
                currentRole = mappedRole;
                currentParts = [...parts];
            }
        }

        if (currentRole !== null) {
            merged.push({ parts: currentParts, role: currentRole });
        }

        return merged;
    }

    private formatTools(tools?: IToolDefinition[]): FunctionDeclaration[] {
        if (!tools) return [];
        return tools.map(t => ({
            description: t.description,
            name: t.name,
            parameters: t.parameters as unknown as Record<string, unknown> // Note SDK Typing is strict, we typecast
        })) as FunctionDeclaration[];
    }

    private parseResponse(response: GenerateContentResponse): UnifiedMessage {
        const candidate = response.candidates?.[0];
        // Safely extract text from parts to avoid SDK property/getter confusion
        let text = "";
        if (candidate?.content?.parts) {
            text = candidate.content.parts.map(p => p.text || "").join("");
        }

        const toolCalls: ToolCall[] = [];
        const mergedCalls = new Map<string, ToolCall>();

        if (candidate?.content?.parts) {
            // First pass: capture the global or part-specific thought_signature
            let messageLevelSignature: string | undefined;
            candidate.content.parts.forEach(part => {
                const partObj = part as Record<string, unknown>;
                const sig = partObj['thought_signature'];
                if (typeof sig === 'string' && sig) {
                    messageLevelSignature = sig;
                }
            });

            candidate.content.parts.forEach((part) => {
                if (part.functionCall) {
                    const call = part.functionCall;
                    const name = call.name;
                    if (name) {
                        const safeArgs = (call.args && typeof call.args === 'object') ? call.args : {};

                        const partObj = part as Record<string, unknown>;
                        const partSignature = partObj['thought_signature'];
                        const finalSignature = typeof partSignature === 'string' ? partSignature : messageLevelSignature;

                        const existing = mergedCalls.get(name);
                        if (existing) {
                            // Merge arguments for partial chunks
                            existing.args = { ...existing.args, ...safeArgs };
                            if (finalSignature && !existing.thought_signature) {
                                existing.thought_signature = finalSignature;
                            }
                        } else {
                            mergedCalls.set(name, {
                                args: { ...safeArgs },
                                name,
                                thought_signature: finalSignature
                            });
                        }
                    }
                }
            });

            mergedCalls.forEach(call => toolCalls.push(call));
        }

        return {
            content: text,
            rawContent: candidate?.content?.parts,
            role: "model",
            toolCalls: toolCalls.length > 0 ? toolCalls : undefined
        };
    }

    // --- Sub-Agent Legacy Adapters (Grounding) ---
    /**
     * Preserved specifically for backwards compat but wrapped correctly.
     * Web grounding goes out through here.
     */
    public async searchWithGrounding(query: string): Promise<{ text: string, tokenCount: number }> {
        return this.retryOperation(async () => {
             const client = await this.getClient();
             const response = await client.models.generateContent({
                 config: { tools: [{ googleSearch: {} }] },
                 contents: `Search for: "${query}". List key facts, dates, and details. Be concise.`,
                 model: this.settings.groundingModel
             });
             return {
                 text: response.text || "",
                 tokenCount: this.extractTokenCount(response, query)
             };
        });
    }

    public async solveWithCode(query: string): Promise<{ text: string, tokenCount: number }> {
        return this.retryOperation(async () => {
             const client = await this.getClient();
             const response = await client.models.generateContent({
                 config: { tools: [{ codeExecution: {} }] },
                 contents: query,
                 model: this.settings.codeModel
             });

             let resultString = "";
             const parts = response.candidates?.[0]?.content?.parts || [];
             for (const part of parts) {
                if (part.text) resultString += part.text + "\n";
                if (part.executableCode) resultString += `\n[Generated Code]\n\`\`\`python\n${part.executableCode.code}\n\`\`\`\n`;
                if (part.codeExecutionResult) resultString += `\n[Execution Result]\n${part.codeExecutionResult.output}\n`;
             }

             return {
                 text: resultString.trim() || "",
                 tokenCount: this.extractTokenCount(response, query)
             };
        });
    }

    // --- IEmbeddingClient Implementation ---

    public get modelName(): string {
        return this.settings.embeddingModel;
    }

    public get dimensions(): number {
        return this.settings.embeddingDimension;
    }

    public async embedQuery(text: string): Promise<{ tokenCount: number; vector: number[] }> {
        const { tokenCount, values } = await this.embedText(text);
        return { tokenCount, vector: values };
    }

    public async embedDocument(text: string, title?: string): Promise<{ tokenCount: number; vectors: number[][] }> {
        const { tokenCount, values } = await this.embedText(text, { title });
        return { tokenCount, vectors: [values] };
    }

    private async embedText(text: string, options: EmbedOptions = {}): Promise<{ values: number[], tokenCount: number }> {
        return this.retryOperation(async () => {
            const client = await this.getClient();
            const config: EmbedContentConfig = {};

            config.outputDimensionality = options.outputDimensionality || this.settings.embeddingDimension;
            if (options.taskType) config.taskType = options.taskType;
            if (options.title) config.title = options.title;

            let modelId = this.settings.embeddingModel;
            if (modelId === 'embedding-001') modelId = MODEL_CONSTANTS.EMBEDDING_001;
            if (modelId === 'embedding-004') modelId = MODEL_CONSTANTS.TEXT_EMBEDDING_004;

            const result = await client.models.embedContent({
                config: config,
                contents: text,
                model: modelId
            });

            const embeddings = result.embeddings;
            if (!embeddings || embeddings.length === 0) {
                throw new ProviderError("No embeddings returned.", "google");
            }
            if (!embeddings[0] || !embeddings[0].values) {
                throw new ProviderError("No embedding values found.", "google");
            }

            return {
                tokenCount: this.extractTokenCount(result, text),
                values: embeddings[0].values
            };
        });
    }

    private extractTokenCount(response: unknown, fallbackText: string): number {
        const res = response as { usageMetadata?: { totalTokenCount?: number, promptTokenCount?: number }; embeddings?: { statistics?: { tokenCount?: number } }[] };
        const count = res.usageMetadata?.totalTokenCount || res.usageMetadata?.promptTokenCount || res.embeddings?.[0]?.statistics?.tokenCount;
        return (typeof count === 'number' && !isNaN(count) && count > 0)
             ? count
             : Math.ceil(fallbackText.length / SEARCH_CONSTANTS.CHARS_PER_TOKEN_ESTIMATE);
    }

    // --- Utility ---

    private async retryOperation<T>(operation: () => Promise<T>, retries: number = this.settings.geminiRetries): Promise<T> {
        let lastError: Error | null = null;
        let delay = 1000;
        for (let attempt = 0; attempt < retries; attempt++) {
            try {
                return await operation();
            } catch (error: unknown) {
                const err = error as { message?: string; status?: number };
                const isTransientError = err.message?.includes("429") || err.status === 429 || err.message?.includes("Failed to fetch");

                if (isTransientError) {
                    logger.warn(`Transient error (${err.message || "unknown"}). Retrying in ${Math.round(delay)}ms...`);
                    lastError = error instanceof Error ? error : new Error(String(error));
                    await new Promise(resolve => setTimeout(resolve, delay));
                    delay *= 2; // Exponential backoff
                } else {
                    const message = err.message || "Unknown error occurred";
                    const status = err.status;
                    throw new ProviderError(message, "google", status);
                }
            }
        }
        throw lastError || new ProviderError("Max retries reached.", "google", 429);
    }
}

import { Client } from "@modelcontextprotocol/sdk/client/index.js";
import { SSEClientTransport } from "@modelcontextprotocol/sdk/client/sse.js";
import { CallToolResult } from "@modelcontextprotocol/sdk/types.js";
import { App, Notice, Platform } from "obsidian";

import { SEARCH_CONSTANTS } from "../constants";
import { MCPServerConfig, VaultIntelligenceSettings } from "../settings/types";
import { IProvider, IToolDefinition, ProviderError } from "../types/providers";
import { logger } from "../utils/logger";

interface McpConnection {
    client: Client;
    config: MCPServerConfig;
    errorMessage?: string;
    pid?: number;
    status: 'connecting' | 'connected' | 'error' | 'untrusted';
    transport: unknown; // StdioClientTransport or SSEClientTransport
}

export class McpClientManager implements IProvider {
    private app: App;
    private settings: VaultIntelligenceSettings;
    private connections = new Map<string, McpConnection>();
    private toolNameMap = new Map<string, { originalName: string; serverId: string }>();

    constructor(app: App, settings: VaultIntelligenceSettings) {
        this.app = app;
        this.settings = settings;
    }

    public async initialize(): Promise<void> {
        // Non-blocking initialization
        Promise.resolve().then(async () => {
            for (const server of this.settings.mcpServers || []) {
                if (server.enabled) {
                    await this.connectServer(server).catch(e => {
                        logger.error(`Failed to connect to MCP server ${server.name}`, e);
                    });
                }
            }
        });
    }

    public async terminate(): Promise<void> {
        for (const [id, connection] of this.connections.entries()) {
            try {
                // Gracefully close client first (sends JSON-RPC shutdown)
                const client = connection.client;
                if (client) await client.close().catch(() => {});

                // For stdio, we explicitly kill the process tree to avoid zombies
                if (connection.config.type === 'stdio' && connection.pid) {
                    if (Platform.isDesktopApp) {
                        try {
                            const { execSync } = require('child_process');
                            if (process.platform === 'win32') {
                                execSync(`taskkill /pid ${connection.pid} /t /f`, { stdio: 'ignore' });
                            } else {
                                process.kill(connection.pid); // Send standard SIGTERM to parent
                            }
                        } catch (e) {
                            logger.warn(`Failed to kill process tree for MCP server ${connection.config.name}:`, e);
                        }
                    }
                }
            } catch (e) {
                logger.error(`Error terminating MCP server ${connection.config.name}:`, e);
            }
        }
        this.connections.clear();
        this.toolNameMap.clear();
    }

    public updateSettings(settings: VaultIntelligenceSettings) {
        this.settings = settings;
        // In a full implementation, we would compare the list and only restart changed servers.
        // For Phase 4 MVP, we assume terminate() is called on unload.
    }

    private async generateTrustHash(config: MCPServerConfig): Promise<string> {
        const payload = JSON.stringify({
            args: config.args,
            command: config.command,
            env: config.env
        });
        const encoder = new TextEncoder();
        const data = encoder.encode(payload);
        const hashBuffer = await crypto.subtle.digest('SHA-256', data);
        const hashArray = Array.from(new Uint8Array(hashBuffer));
        const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
        return hashHex;
    }

    public checkTrustState(config: MCPServerConfig): { trusted: boolean; hash: string } {
        // Assume everything else trusted except stdio (which runs local processes)
        if (config.type !== 'stdio') return { hash: '', trusted: true };
        return { hash: '', trusted: false }; // Will map implementation later in connectServer
    }

    private async connectServer(server: MCPServerConfig): Promise<void> {
        logger.info(`Connecting to MCP server ${server.name}...`);

        if (server.type === 'stdio') {
            if (!Platform.isDesktopApp) {
                logger.warn(`Skipping stdio MCP server ${server.name} on Mobile.`);
                return;
            }

            // Trust Hash Security
            const currentHash = await this.generateTrustHash(server);
            const storedHash = window.localStorage.getItem(`vi-mcp-trust-${server.id}`);
            if (currentHash !== storedHash) {
                logger.warn(`MCP server ${server.name} untrusted. Blocking execution.`);
                this.connections.set(server.id, {
                    client: null as unknown,
                    config: server,
                    errorMessage: 'Untrusted configuration. Please approve in settings.',
                    status: 'untrusted',
                    transport: null
                });
                return;
            }

            // eslint-disable-next-line no-undef, @typescript-eslint/no-require-imports -- dynamic require
            const { StdioClientTransport } = require('@modelcontextprotocol/sdk/client/stdio.js');

            // Merge Environments
            // eslint-disable-next-line no-undef -- need process env
            let mergedEnv = { ...process.env };
            if (server.env) {
                try {
                    // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment -- json
                    const customEnv = JSON.parse(server.env);
                    mergedEnv = { ...mergedEnv, ...customEnv };
                } catch (e) {
                    logger.warn(`Failed to parse custom environment for MCP server ${server.name}`);
                }
            }

            // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call -- dynamic client
            const transport = new StdioClientTransport({
                args: server.args || [],
                command: server.command!,
                env: mergedEnv
            });

            // Note: StdioClientTransport spawns the process internally when start() is called.
            // But we need the PID for killing. It doesn't expose it cleanly, so we might need a workaround.
            // For now, we instantiate the SDK and hope it doesn't leave zombies.

            const client = new Client({
                name: "vault-intelligence",
                version: "1.0.0"
            }, {
                capabilities: {}
            });

            try {
                await client.connect(transport);
                this.connections.set(server.id, {
                    client,
                    config: server,
                    pid: (transport as unknown as { _process?: { pid: number } })._process?.pid, // internal SDK access workaround
                    status: 'connected',

                    transport
                });
                logger.info(`MCP Server ${server.name} connected.`);
            } catch (error) {
                logger.error(`MCP Server ${server.name} connection failed.`, error);
                this.connections.set(server.id, {
                    client: null as unknown as Client,
                    config: server,
                    errorMessage: String(error),
                    status: 'error',
                    transport: null
                });
            }

        } else if (server.type === 'sse') {
            if (!server.url) return;
            // eslint-disable-next-line @typescript-eslint/no-deprecated
            const transport = new SSEClientTransport(new URL(server.url));
            const client = new Client({
                name: "vault-intelligence",
                version: "1.0.0"
            }, {
                capabilities: {}
            });

            try {
                await client.connect(transport);
                this.connections.set(server.id, {
                    client,
                    config: server,
                    status: 'connected',
                    transport
                });
                logger.info(`MCP Server ${server.name} connected.`);
            } catch (error) {
                logger.error(`MCP Server ${server.name} connection failed.`, error);
                this.connections.set(server.id, {
                    // eslint-disable-next-line @typescript-eslint/no-explicit-any, @typescript-eslint/no-unsafe-assignment -- internal reference
                    client: null as any,
                    config: server,
                    errorMessage: String(error),
                    status: 'error',
                    transport: null
                });
            }
        }
    }

    public async getAvailableTools(): Promise<IToolDefinition[]> {
        const tools: IToolDefinition[] = [];
        this.toolNameMap.clear();

        for (const [serverId, connection] of this.connections.entries()) {
            if (connection.status !== 'connected' || !connection.client) continue;

            try {
                const response = await connection.client.listTools();
                for (const tool of response.tools) {
                    // Tool Name Sanitization & Collisions
                    const safeServerId = serverId.replace(/[^a-zA-Z0-9_-]/g, '');
                    const safeToolName = tool.name.replace(/[^a-zA-Z0-9_-]/g, '');
                    let compositeName = `mcp__${safeServerId}__${safeToolName}`;

                    if (compositeName.length > 64) {
                        const hashBuffer = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(tool.name));
                        const hashHex = Array.from(new Uint8Array(hashBuffer)).map(b => b.toString(16).padStart(2, '0')).join('');
                        const shortHash = hashHex.substring(0, 8);
                        compositeName = compositeName.substring(0, 64 - 8) + shortHash;
                    }

                    this.toolNameMap.set(compositeName, { originalName: tool.name, serverId });

                    tools.push({
                        description: `[MCP: ${connection.config.name}] ${tool.description || ''}`,
                        name: compositeName,
                        // eslint-disable-next-line @typescript-eslint/no-explicit-any, @typescript-eslint/no-unsafe-assignment
                        parameters: (tool.inputSchema as any) || { properties: {}, type: "object" }
                    });
                }
            } catch (error) {
                logger.error(`Failed to list tools for MCP server ${connection.config.name}`, error);
            }
        }

        return tools;
    }

    public async executeTool(namespaceName: string, args: Record<string, unknown>): Promise<{ text: string }> {
        const mapping = this.toolNameMap.get(namespaceName);
        if (!mapping) throw new ProviderError(`Unrecognized MCP tool namespace or server disconnected: ${namespaceName}`, "mcp");

        const connection = this.connections.get(mapping.serverId);
        if (!connection || connection.status !== 'connected') {
            throw new ProviderError(`MCP server ${mapping.serverId} is not connected.`, "mcp");
        }

        if (connection.config.type === 'sse') {
            // Mobile SSE Resiliency: Simple check to see if we're connected
            try {
                // Ideally sending a ping, but SDK lacks ping. We catch execution errors fast.
            } catch (e) {
                logger.warn("SSE stream might be closed, should retry.");
            }
        }

        try {
            // Include strict timeout
            const timeoutPromise = new Promise<never>((_, reject) => setTimeout(() => reject(new Error("MCP Tool Execution Timeout")), 60000));
            const execPromise = connection.client.callTool({
                arguments: args,
                name: mapping.originalName
            });

            const result = await Promise.race([execPromise, timeoutPromise]) as CallToolResult;

            let outputText = "";
            if (result.content && result.content.length > 0) {
                outputText = result.content.map(c => {
                    if (c.type === 'text') return c.text;
                    return `[${c.type} content]`;
                }).join('\n');
            }

            if (result.isError) {
                return { text: `[Error from MCP Tool] \n${outputText}` };
            }

            // Payload Truncation
            if (outputText.length > SEARCH_CONSTANTS.TOOL_RESPONSE_TRUNCATE_LIMIT) {
                outputText = outputText.substring(0, SEARCH_CONSTANTS.TOOL_RESPONSE_TRUNCATE_LIMIT) + "\n...[TRUNCATED BY VAULT INTELLIGENCE]...";
            }

            return { text: outputText || "[Tool executed successfully with no output]" };

        } catch (error) {
            throw new ProviderError(`Failed to execute MCP tool ${mapping.originalName}: ${String(error)}`, "mcp");
        }
    }
}

import { Setting, ButtonComponent, ToggleComponent } from "obsidian";

import { SettingsTabContext } from "../SettingsTabContext";
import { MCPServerConfig } from "../types";

export function renderMcpSettings({ containerEl, plugin }: SettingsTabContext): void {
    containerEl.empty();

    // eslint-disable-next-line obsidianmd/ui/sentence-case -- MCP acronym
    containerEl.createEl("h3", { text: "External MCP servers" });
    containerEl.createEl("p", { 
        text: "Connect external model context protocol (MCP) servers to allow AI models to perform external actions, such as fetching weather, reading databases, or integrating with other tools. Caution: Avoid storing plaintext secrets in the environment variables; future versions will support Secure Storage interpolation." 
    });

    const listContainer = containerEl.createDiv("mcp-server-list");
    listContainer.setCssProps({ "margin-bottom": "2em" });

    const renderList = () => {
        listContainer.empty();
        const servers = plugin.settings.mcpServers || [];

        if (servers.length === 0) {
            // eslint-disable-next-line obsidianmd/ui/sentence-case -- MCP acronym
            listContainer.createEl("em", { text: "No MCP servers configured." });
        } else {
            servers.forEach((server, index) => {
                const serverDiv = listContainer.createDiv("mcp-server-item");
                serverDiv.setCssProps({ "border": "1px solid var(--background-modifier-border)", "border-radius": "8px", "margin-bottom": "1em", "padding": "1em" });

                const headerRow = serverDiv.createDiv("mcp-server-header");
                headerRow.setCssProps({ "align-items": "center", "display": "flex", "justify-content": "space-between", "margin-bottom": "0.5em" });

                const title = headerRow.createEl("h4", { text: server.name || "Unnamed Server" });
                title.setCssProps({ "margin": "0" });

                // Status indicator
                const mcpManager = plugin.mcpClientManager as { connections?: Map<string, { status: string }> };
                const connection = mcpManager.connections ? mcpManager.connections.get(server.id) : undefined;
                let status = 'disabled';
                if (connection) status = connection.status;
                else if (server.enabled) status = 'disconnected';

                const statusBadge = headerRow.createSpan("mcp-status");
                statusBadge.textContent = status.toUpperCase();
                statusBadge.setCssProps({ "border-radius": "4px", "font-size": "0.8em", "margin-left": "10px", "padding": "2px 6px" });
                if (status === 'connected') statusBadge.setCssProps({ "background-color": "var(--interactive-success)" });
                else if (status === 'error' || status === 'untrusted') statusBadge.setCssProps({ "background-color": "var(--interactive-error)" });
                else statusBadge.setCssProps({ "background-color": "var(--background-modifier-border)" });

                new ToggleComponent(headerRow)
                    .setValue(server.enabled)
                    .onChange(async (v) => {
                        if (plugin.settings.mcpServers && plugin.settings.mcpServers[index]) plugin.settings.mcpServers[index].enabled = v;
                        await plugin.saveSettings(false);
                        renderList(); // re-render to reflect disabled state logic if needed
                    });

                const detailsRow = serverDiv.createDiv("mcp-server-details");
                detailsRow.createEl("p", { cls: "setting-item-description", text: `Type: ${server.type === 'stdio' ? 'Stdio (Local Process)' : 'SSE (Remote URL)'}` });

                const errMessage = (connection as { errorMessage?: string })?.errorMessage;
                if (status === 'error' && errMessage) {
                    const err = detailsRow.createEl("p", { cls: "setting-item-description", text: `Error: ${errMessage}` });
                    err.setCssProps({ "color": "var(--text-error)" });
                }

                const btnRow = serverDiv.createDiv("mcp-server-actions");
                btnRow.setCssProps({ "margin-top": "1em" });

                new ButtonComponent(btnRow)
                    .setButtonText("Edit")
                    .onClick(() => {
                        renderEditor(server, index);
                    });

                new ButtonComponent(btnRow)
                    .setButtonText("Remove")
                    .setWarning()
                    .onClick(async () => {
                        plugin.settings.mcpServers.splice(index, 1);
                        await plugin.saveSettings(false);
                        renderList();
                    });
            });
        }
    };

    const renderEditor = (server: MCPServerConfig | null, index: number = -1) => {
        containerEl.empty();
        containerEl.createEl("h3", { text: server ? "Edit MCP server" : "Add MCP server" });

        let currentConfig: MCPServerConfig = server ? JSON.parse(JSON.stringify(server)) as MCPServerConfig : {
            enabled: true,
            id: crypto.randomUUID(),
            name: "",
            requireExplicitConfirmation: true,
            type: "stdio",
        };

        new Setting(containerEl)
            .setName("Server name")
            .setDesc("A friendly name for this server (e.g., 'github info')")
            .addText(text => text
                .setValue(currentConfig.name)
                .onChange(v => currentConfig.name = v)
            );

        new Setting(containerEl)
            .setName("Connection type")
            .setDesc("Stdio runs a local binary. SSE connects to a remote URL.")
            .addDropdown(drop => drop
                .addOptions({ "sse": "SSE URL (remote)", "stdio": "Stdio (desktop only)" })
                .setValue(currentConfig.type)
                .onChange(v => {
                    currentConfig.type = v as "stdio" | "sse";
                    renderEditor(currentConfig, index); // re-render fields
                })
            );

        if (currentConfig.type === "stdio") {
            const cmdSetting = new Setting(containerEl)
                .setName("Command")
                .setDesc("Absolute path to the executable (e.g. /usr/local/bin/python or /opt/homebrew/bin/node). Avoid wrappers like 'npx' or relative paths.")
                .addText(text => text
                    .setValue(currentConfig.command || "")
                    .onChange(v => currentConfig.command = v)
                );
            // Highlight warning
            cmdSetting.descEl.setCssProps({ "color": "var(--text-warning)" });

            new Setting(containerEl)
                .setName("Arguments")
                .setDesc("Enter arguments line by line (one argument per line). Avoids command-line string escaping issues.")
                .addTextArea(text => {
                    text.setValue((currentConfig.args || []).join('\n'));
                    text.onChange(v => {
                        currentConfig.args = v.split('\n').map(s => s.trim()).filter(s => s.length > 0);
                    });
                    text.inputEl.rows = 3;
                    return text;
                });

            const envSetting = new Setting(containerEl)
                .setName("Environment variables")
                .setDesc("Provide as valid JSON: {\"TOKEN\": \"value\"}. WARNING: Do NOT put plaintext secrets here if you sync your vault across untrusted devices. They will be merged with your system environment.")
                .addTextArea(text => {
                    text.setValue(currentConfig.env || "");
                    text.onChange(v => currentConfig.env = v);
                    text.inputEl.rows = 4;
                    return text;
                });
            envSetting.descEl.setCssProps({ "color": "var(--text-warning)" });
        } else {
            new Setting(containerEl)
                // eslint-disable-next-line obsidianmd/ui/sentence-case -- SSE acronym
                .setName("SSE URL")
                // eslint-disable-next-line obsidianmd/ui/sentence-case -- HTTP acronym
                .setDesc("The full HTTP(S) url of the SSE endpoint.")
                .addText(text => text
                    .setValue(currentConfig.url || "")
                    .onChange(v => currentConfig.url = v)
                );
        }

        new Setting(containerEl)
            .setName("Require explicit confirmation")
            .setDesc("If on, you will be prompted to confirm every execution of this server's tools. Turn off only for explicitly safe, read-only tools.")
            .addToggle(toggle => toggle
                .setValue(currentConfig.requireExplicitConfirmation)
                .onChange(v => currentConfig.requireExplicitConfirmation = v)
            );

        const btnRow = containerEl.createDiv();
        btnRow.setCssProps({ "display": "flex", "gap": "1em", "margin-top": "2em" });

        new ButtonComponent(btnRow)
            .setButtonText("Cancel")
            .onClick(() => {
                renderMcpSettings({ app: plugin.app, containerEl, plugin }); // Go back
            });

        new ButtonComponent(btnRow)
            .setButtonText("Save")
            .setCta()
            .onClick(async () => {
                if (!plugin.settings.mcpServers) plugin.settings.mcpServers = [];

                if (index >= 0) {
                    plugin.settings.mcpServers[index] = currentConfig;
                } else {
                    plugin.settings.mcpServers.push(currentConfig);
                }
                await plugin.saveSettings(false);
                renderMcpSettings({ app: plugin.app, containerEl, plugin }); // Go back
            });
    };

    renderList();

    if ((plugin.settings.mcpServers || []).length > 0) {
        containerEl.createEl("br");
    }

    new ButtonComponent(containerEl)
        // eslint-disable-next-line obsidianmd/ui/sentence-case -- MCP acronym
        .setButtonText("Add MCP server")
        .setCta()
        .onClick(() => {
            renderEditor(null);
        });
}

